mapper.select:
SELECT a.process_id, a.process_nm, a.remark as processDesc, c.rev_no, c2.rev_nm, CONCAT(a.process_nm, ' (', c2.rev_nm, '-', c.rev_no, ')') as prcsNm FROM esg.tb_process_info a LEFT JOIN esg.tb_orgn_map b ON b.target_id = a.process_id INNER JOIN esg.tb_safety_and_health_info_survey c ON c.process_id = b.target_id INNER JOIN esg.tb_process_work_cnfm c2 ON c.process_id = c2.process_id AND c.rev_no = c2.rev_no WHERE c.write_year = #{writeYear} AND a.comp_id = #{compId} AND b.target_type = 'process' AND b.orgn_id = #{orgnId} AND c.use_yn = 'Y' AND c.confirm_yn = 'Y'
AND a.process_id NOT IN
#{processId}

SELECT a.write_year, a.doc_type, a.doc_no, a.process_id, MIN(a.prcs_work_id) AS prcs_work_id, MIN(a.work_detail_id) AS work_detail_id, a.work_type, a.content, b.rev_no FROM esg.tb_safety_and_health_info_survey_detail a INNER JOIN esg.tb_safety_and_health_info_survey b ON b.write_year = a.write_year AND b.doc_type = a.doc_type AND b.doc_no = a.doc_no WHERE b.doc_type = 'SAHIS' AND b.write_year = #{writeYear} AND a."content" is not NULL AND b.use_yn = 'Y' AND b.rev_no IN
#{revNo}
AND b.process_id IN
#{processId}
GROUP BY a.write_year, a.doc_type, a.doc_no, a.process_id, a.work_type, a.content, b.rev_no ORDER BY work_detail_id DESC

mapper.update:
UPDATE esg.tb_classification_process_equip_msds
SET
confirm_yn = #{confirmYn},

	confirm_dt = now(),


	confirm_dt = null,

updated_at = now(),
updated_by = #{updatedBy}
WHERE write_year = #{writeYear}
AND doc_type = #{docType}
AND doc_no = #{docNo}

		UPDATE esg.tb_classification_process_equip_msds
		   SET use_yn = 'N',
	           updated_at = now(),
	           updated_by = #{updatedBy}
         WHERE WRITE_YEAR = #{writeYear}
           AND DOC_TYPE = #{docType}
           AND DOC_NO = #{docNo}
           AND COMP_ID = #{compId}

